    std::uint64_t aWandererK = *pWandererK;
    std::uint64_t aNonceWordA = TwistMix64::DiffuseC(pNonce * 0xC5F0D5B49AE2A6EFULL + 0xF13D75C0EC1EE8FEULL);
    std::uint64_t aNonceWordB = TwistMix64::DiffuseC(pNonce * 0xE6E575BF72424BBFULL + 0x9981244EAE1337D7ULL);
    std::uint64_t aNonceWordC = TwistMix64::DiffuseB(pNonce * 0x98030732896453B3ULL + 0xD1EF700C9F6AF3C4ULL);
