    std::uint64_t aNonceWordJ = TwistMix64::DiffuseB(pNonce * 0x929ECBA510E1C74FULL + 0xB0EDC423B5BCB2EFULL);
    std::uint64_t aNonceWordK = TwistMix64::DiffuseA(pNonce * 0x94A04C90B261737FULL + 0x9A78C4EFB179E5C2ULL);
    std::uint64_t aNonceWordL = TwistMix64::DiffuseB(pNonce * 0x9BB1928C1524C76DULL + 0xC5886CB2485F58F3ULL);
    std::uint64_t aNonceWordM = TwistMix64::DiffuseC(pNonce * 0xDC28B3E251E6AE4FULL + 0x9F4D47B81C8DFEA2ULL);
    std::uint64_t aNonceWordN = TwistMix64::DiffuseA(pNonce * 0x80C57F39891273E3ULL + 0xD55B34F22BBE77F5ULL);
