            aOrbiterF = (aOrbiterF + aOrbiterI) + 0x6F84E66A936533C7ULL;
            aOrbiterG = (aOrbiterG ^ aOrbiterF) ^ 0x98B149D9BA6BF2D8ULL;
            aOrbiterG = RotL64((aOrbiterG * 0x8AED739788C8D989ULL), 13U);
            //
            aOrbiterG = (aOrbiterG + aOrbiterH) + 0x2740FC133C610878ULL;
